const JSZip = require('jszip');

// Templates embutidos como base64
const TEMPLATE_PROCURACAO = '';
const TEMPLATE_CONTRATO = '';

function isRed(rPr) {
  if (!rPr) return false;
  // Check for color element with val FF0000
  const colorMatch = rPr.match(/<w:color[^>]+w:val="FF0000"/);
  return !!colorMatch;
}

function substituirCamposVermelhos(xml, campos) {
  // Find all <w:r> runs with red color and replace sequentially
  let idx = 0;
  
  // Replace red runs sequentially
  const result = xml.replace(/<w:r[ >][\s\S]*?<\/w:r>/g, (match) => {
    // Check if this run has red color
    const rPrMatch = match.match(/<w:rPr>([\s\S]*?)<\/w:rPr>/);
    if (rPrMatch && isRed(rPrMatch[0])) {
      // Get current text
      const tMatch = match.match(/<w:t[^>]*>([\s\S]*?)<\/w:t>/);
      if (tMatch && tMatch[1].trim() && idx < campos.length) {
        const valor = campos[idx] || '';
        idx++;
        return match.replace(/<w:t[^>]*>[\s\S]*?<\/w:t>/, 
          `<w:t xml:space="preserve">${valor}</w:t>`);
      }
    }
    return match;
  });
  
  return result;
}

module.exports = async function handler(req, res) {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

  if (req.method === 'OPTIONS') return res.status(200).end();
  if (req.method !== 'POST') return res.status(405).json({ error: 'Method not allowed' });

  try {
    const { tipo, dados: d, financeiro: fin } = req.body;
    
    const hoje = new Date();
    const meses = ['janeiro','fevereiro','março','abril','maio','junho','julho','agosto','setembro','outubro','novembro','dezembro'];
    const dia = String(hoje.getDate());
    const mes = meses[hoje.getMonth()];
    const ano = String(hoje.getFullYear());

    const templateB64 = tipo === 'procuracao' ? TEMPLATE_PROCURACAO : TEMPLATE_CONTRATO;
    const templateBuf = Buffer.from(templateB64, 'base64');
    
    const zip = await JSZip.loadAsync(templateBuf);
    const docXml = await zip.file('word/document.xml').async('string');
    
    let novoXml = docXml;
    
    if (tipo === 'procuracao') {
      const campos = [
        d.nome.toUpperCase(),
        'brasileiro(a)',
        d.estado_civil,
        d.profissao,
        d.rg + (d.orgao_expeditor ? ', expedido pela ' + d.orgao_expeditor : ''),
        d.cpf,
        d.rua,
        d.numero,
        d.bairro,
        d.cidade + ' - ' + d.estado + ', CEP ' + d.cep,
        d.email,
        dia,
        mes,
        d.nome.toUpperCase(),
      ];
      novoXml = substituirCamposVermelhos(docXml, campos);
      
    } else {
      // Contrato
      const parcelas = fin.parcelas || [];
      const metade = Math.ceil(parcelas.length / 2);
      const esq = parcelas.slice(0, metade);
      const dir = parcelas.slice(metade);
      
      const campos = [
        // Para 6: dados cliente
        d.nome.toUpperCase(),
        'brasileiro(a)',
        d.estado_civil,
        d.profissao,
        d.cpf,
        d.rua + ', ' + d.numero + ', ' + d.bairro + ', ' + d.cidade + ' - ' + d.estado + ', CEP ' + d.cep,
        d.email,
        // Para 13: processo
        fin.numeroProcesso,
        // Para 19: honorários
        fin.valorTotal + ' (' + fin.valorTotalExtenso + ')',
        parcelas[0]?.valor || '',
        fin.numParcelasRestantes + ' parcelas de ' + fin.valorParcela,
        // Para 91: data
        dia,
        mes,
        // Para 96: assinatura
        d.nome.toUpperCase(),
      ];
      novoXml = substituirCamposVermelhos(docXml, campos);
      
      // Substituir tabela de pagamentos
      // Para cada célula da tabela com cor vermelha, substituir em ordem
      // Montar lista de valores da tabela
      const tabelaValores = [];
      esq.forEach(p => { tabelaValores.push(p.label + ':'); tabelaValores.push(p.valor); tabelaValores.push(p.data); });
      dir.forEach(p => { tabelaValores.push(p.label + ':'); tabelaValores.push(p.valor); tabelaValores.push(p.data); });
      tabelaValores.push(fin.valorTotal); // Total
      
      // The table values are already handled by the sequential replacement above
      // since substituirCamposVermelhos processes all red runs in document order
    }
    
    zip.file('word/document.xml', novoXml);
    const outputBuf = await zip.generateAsync({ type: 'nodebuffer', compression: 'DEFLATE' });
    
    const nomeArquivo = tipo === 'procuracao'
      ? `Procuracao_${d.nome.replace(/\s+/g, '_')}.docx`
      : `Contrato_${d.nome.replace(/\s+/g, '_')}.docx`;
    
    res.setHeader('Content-Type', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document');
    res.setHeader('Content-Disposition', `attachment; filename="${nomeArquivo}"`);
    return res.status(200).send(outputBuf);
    
  } catch (error) {
    return res.status(500).json({ error: error.message, stack: error.stack });
  }
};
